from flask import Flask, jsonify
from pymemcache.client.base import Client

app = Flask(__name__)
memcached_client = Client(('localhost', 11211))

def get_data_from_database(query):
    # Simulate a database query
    return f"Data for {query}"

@app.route('/data/<string:query>')
def data(query):
    cached_data = memcached_client.get(query)
    if cached_data:
        return jsonify({'data': cached_data.decode('utf-8'), 'source': 'cache'})
    
    # If not in cache, fetch from database
    db_data = get_data_from_database(query)
    memcached_client.set(query, db_data.encode('utf-8'), expire=300)  # Cache for 5 minutes
    
    return jsonify({'data': db_data, 'source': 'database'})

if __name__ == '__main__':
    app.run(debug=True)